class Solution {
    public int minimizedStringLength(String s) {
        int n = s.length();
        int[] last = new int[26];
        Arrays.fill(last, n);
        for (int i = n - 1; i >= 0; i--) {
            last[s.charAt(i) - 'a'] = i;
        }
        int res = n;
        for (int i = 0; i < n; i++) {
            int left = last[s.charAt(i) - 'a'];
            if (left == n) continue;
            res = Math.min(res, n - (left + (n - i - 1) - (left - i)));
        }
        return res;
    }
}
```

